```cpp
#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    // Create buffer_adaptor from input buffer
    auto adaptor = hexi::buffer_adaptor<std::span<const uint8_t>>(const_cast<std::span<const uint8_t>&>(buffer));

    NetworkPacket packet;

    // Read packet_id using operator>>
    adaptor >> packet.packet_id;

    // Read username using operator>> with prefixed<std::string>
    adaptor >> hexi::prefixed(packet.username);

    // Read scores vector: first read count, then use read_container
    uint32_t score_count;
    adaptor >> score_count;
    adaptor.read_container(packet.scores, score_count);

    // Read metadata as null-terminated string using span()
    packet.metadata = adaptor.span<hexi::null_terminated<std::string>>();

    // Skip any remaining padding bytes
    size_t remaining_bytes = adaptor.size();
    if (remaining_bytes > 0) {
        adaptor.skip(remaining_bytes);
    }

    return packet;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    PacketInfo info;

    // Create buffer_adaptor from input buffer
    auto adaptor = hexi::buffer_adaptor<std::span<const uint8_t>>(const_cast<std::span<const uint8_t>&>(buffer));

    // Use span() to get zero-copy view of packet_id
    auto id_span = adaptor.span<uint32_t>(1);
    info.packet_id = id_span[0];

    // Read username using prefixed<std::string_view>
    adaptor >> hexi::prefixed(info.username);

    // Skip the scores vector
    uint32_t score_count;
    adaptor >> score_count;
    adaptor.skip(score_count * sizeof(uint32_t));

    return info;
}
```

