struct DataResult {
    uint8_t data_type;
    std::vector<uint32_t> int_items;
    std::vector<float> float_items;
};

DataResult preview_and_read_data(const std::span<const uint8_t> buffer) {
    // Create buffer_adaptor from the input buffer
    hexi::buffer_adaptor<std::span<const uint8_t>> adaptor(const_cast<std::span<uint8_t>>(buffer));

    DataResult result;

    // Use preview function to read data_type without advancing read pointer
    result.data_type = adaptor.preview<uint8_t>();

    // Calculate total data size needed for reading
    // 1 byte (data_type) + 4 bytes (item_count) + (item_count * sizeof(item))
    // Since both uint32_t and float are 4 bytes, we can calculate as:
    // 5 + (item_count * 4) bytes

    // Check if buffer has enough data for the entire structure
    if (adaptor.size() < 5) {
        // Not enough data for header, return empty result
        return result;
    }

    // Create binary_stream for reading
    hexi::binary_stream<decltype(adaptor)> stream(adaptor);

    // Read item_count
    uint32_t item_count;
    stream.get(&item_count, 1);

    // Check if buffer has enough data for all items
    size_t total_item_size = item_count * 4; // 4 bytes per item
    if (adaptor.size() < 5 + total_item_size) {
        // Not enough data for all items, return partial result
        return result;
    }

    // Read items based on data_type
    if (result.data_type == 0) { // Integers
        result.int_items.resize(item_count);
        stream.get(result.int_items.data(), item_count);
    } else if (result.data_type == 1) { // Floats
        result.float_items.resize(item_count);
        stream.get(result.float_items.data(), item_count);
    }

    return result;
}
