#include <hexi/file_buffer.h>
#include <vector>
#include <cstdint>
#include <filesystem>

std::vector<uint8_t> preview_file_header(const std::filesystem::path& file_path, size_t header_size) {
    // Create a hexi::file_buffer object using the provided file path
    hexi::file_buffer buffer(file_path);

    // Check if the file buffer is in a valid state (no errors occurred during initialization)
    if (buffer.error()) {
        return {}; // Return empty vector if file opening failed
    }

    // If the header_size is zero or the file is empty, return an empty vector
    if (header_size == 0 || buffer.empty()) {
        return {};
    }

    // Ensure we don't try to read more than available file size
    size_t actual_size = header_size;
    if (actual_size > buffer.size()) {
        actual_size = buffer.size();
    }

    // Create a vector to store the header data with the appropriate size
    std::vector<uint8_t> header_data(actual_size);

    // Use the copy method of the file_buffer object to copy the header data without advancing the read pointer
    buffer.copy(header_data.data(), actual_size);

    // Return the vector containing the header data
    return header_data;
}
```

